UPDATE desafios d JOIN temas t ON t.id = d.tema_id SET d.icone='viagem' WHERE t.nome='Aprimoramento do Atendimento ao Cidadão e Acesso à Justiça (Tema 2)' AND d.pergunta='Como podemos facilitar o processamento dos pedidos de autorização de viagem para menores, feito pelos pais e responsáveis, para que seja menos custoso a eles e ao judiciário?';
